// === Arduino controller for turntable + strobe trigger ===
#include <Stepper.h>
#include <Wire.h>

const int STEPS_PER_REV=2048,STROBE_PIN=6,TRIG_PIN=7;
const int STEPS_PER_SECTOR=STEPS_PER_REV/36;
Stepper motor(STEPS_PER_REV,8,10,9,11);
bool sector_done=false;
int sector=0;
float porosity_results[36];
bool fault=false;

// === Turntable ===
void turntable_init(){motor.setSpeed(5);}
void turntable_step(){motor.step(STEPS_PER_SECTOR);delay(500);}

// === IR Strobe ===
void strobe_init(){pinMode(STROBE_PIN,OUTPUT);digitalWrite(STROBE_PIN,LOW);}
void strobe_fire(){digitalWrite(STROBE_PIN,HIGH);delay(1);digitalWrite(STROBE_PIN,LOW);}

// === Capture Trigger to ESP32-CAM ===
void cam_trigger_init(){pinMode(TRIG_PIN,OUTPUT);digitalWrite(TRIG_PIN,LOW);}
void cam_capture(){strobe_fire();digitalWrite(TRIG_PIN,HIGH);delay(50);digitalWrite(TRIG_PIN,LOW);}

// === Serial Result Parser from RPi ===
float parse_porosity(){
  unsigned long t=millis();
  while(millis()-t<5000){if(Serial.available()){float v=Serial.parseFloat();if(v>=0&&v<=100)return v;}}
  return -1.0f;}

// === Fault Handler ===
bool fault_check(float p){if(p<0){Serial.println("FAULT:VISION_TIMEOUT");return true;}if(p>2.0f){Serial.println("FAIL:POROSITY");return true;}return false;}

void setup(){
  Serial.begin(115200);
  turntable_init();strobe_init();cam_trigger_init();
  Serial.println("Coating QC Inspector Ready");
}

void loop(){
  if(sector>=36){Serial.println("SCAN_COMPLETE");delay(60000);sector=0;return;}
  turntable_step();
  cam_capture();
  float p=parse_porosity();
  fault=fault_check(p);
  porosity_results[sector]=p;
  Serial.print("SEC:");Serial.print(sector);Serial.print(" P=");Serial.print(p,2);Serial.println("%");
  sector++;
}
